import{_ as a,o as i,c as l,ao as t}from"./chunks/framework.Cg2N26K4.js";const h=JSON.parse('{"title":"Roadmap","description":"","frontmatter":{},"headers":[],"relativePath":"roadmap.md","filePath":"roadmap.md","lastUpdated":null}'),o={name:"roadmap.md"};function r(n,e,d,s,p,c){return i(),l("div",null,[...e[0]||(e[0]=[t('<h1 id="Roadmap" tabindex="-1">Roadmap <a class="header-anchor" href="#Roadmap" aria-label="Permalink to &quot;Roadmap {#Roadmap}&quot;">​</a></h1><p>This page mirrors the repository roadmap. It is evidence-gated: a capability is public only when code, tests, documentation, validation status, and the R-Julia contract agree.</p><h2 id="Current-Status" tabindex="-1">Current Status <a class="header-anchor" href="#Current-Status" aria-label="Permalink to &quot;Current Status {#Current-Status}&quot;">​</a></h2><p>Phase 0 is complete. Phase 1 has started.</p><p>Implemented:</p><ul><li><p>package scaffold and CI;</p></li><li><p>control/backend markers;</p></li><li><p>placeholder fitting entry points;</p></li><li><p>pedigree validation and topological sorting;</p></li><li><p>direct sparse <code>Ainv</code> construction for validated pedigrees;</p></li><li><p>optional external R-side <code>nadiv::Mrode9</code> / <code>nadiv::makeAinv()</code> comparator evidence for <code>pedigree_inverse()</code>;</p></li><li><p>low-level animal-model spec validation;</p></li><li><p>dense Gaussian likelihood evaluation with a <code>max_dense_cells</code> guard;</p></li><li><p>sparse REML likelihood evaluation at supplied variance components via the Henderson MME determinant identity;</p></li><li><p>experimental dense variance-component optimization;</p></li><li><p>experimental dense EBV/BLUP, heritability, PEV, and reliability extraction;</p></li><li><p>experimental direct payload fitting target for <code>y</code>, <code>X</code>, <code>Z</code>, <code>Ainv</code>;</p></li><li><p>sparse Henderson MME solving at supplied variance components;</p></li><li><p>sparse CSC marshalling helper for R sparse matrix slots;</p></li><li><p>external opt-in R bridge evidence from <code>hsquared</code> head <code>9eabf0d</code>;</p></li><li><p>external R PEV/reliability bridge extractor contract evidence from <code>hsquared</code> head <code>78ba5ff</code>, with Julia payload widening still planned.</p></li><li><p>external sparse <code>Z</code> bridge marshalling evidence from <code>hsquared</code> head <code>398e019</code>.</p></li></ul><p>Not implemented:</p><ul><li><p>sparse production animal-model REML/ML or AI-REML fitting;</p></li><li><p>production sparse EBVs/BLUPs, reliability, and prediction error variance;</p></li><li><p>production R-to-Julia fitting bridge.</p></li></ul><h2 id="Phase-1:-Simple-Gaussian-Animal-Model" tabindex="-1">Phase 1: Simple Gaussian Animal Model <a class="header-anchor" href="#Phase-1:-Simple-Gaussian-Animal-Model" aria-label="Permalink to &quot;Phase 1: Simple Gaussian Animal Model {#Phase-1:-Simple-Gaussian-Animal-Model}&quot;">​</a></h2><p>Next engine targets:</p><ol><li><p>Mrode-style validation and comparator checks;</p></li><li><p>lockstep R/Julia decision on PEV/reliability bridge payload fields;</p></li><li><p>relationship-object marshalling beyond sparse <code>Z</code> and stable production engine controls;</p></li><li><p>production sparse covariance/precision computations;</p></li><li><p>AI-REML or a documented sparse optimizer path;</p></li><li><p>production sparse reliability and prediction error variance.</p></li></ol><h2 id="Later-Phases" tabindex="-1">Later Phases <a class="header-anchor" href="#Later-Phases" aria-label="Permalink to &quot;Later Phases {#Later-Phases}&quot;">​</a></h2><ul><li><p>Phase 2: repeatability, maternal, common-environment, sire, and related standard animal-model extensions.</p></li><li><p>Phase 3: multivariate Gaussian animal models.</p></li><li><p>Phase 4: factor-analytic G matrices.</p></li><li><p>Phase 5: genomic and single-step models.</p></li><li><p>Phase 6: non-Gaussian and GLLVM-style animal models.</p></li><li><p>Phase 7: non-standard inheritance.</p></li><li><p>Phase 8: huge-scale and accelerator strategy.</p></li></ul><p>Every new public capability must update the status tables, validation debt, tests, docs, and after-task report in the same slice.</p>',14)])])}const u=a(o,[["render",r]]);export{h as __pageData,u as default};
